<?php require __DIR__.'/includes/auth.php'; $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ if(!verify_csrf($_POST['csrf']??'')) $error='Invalid CSRF token.'; elseif(login_user($_POST['email']??'',$_POST['password']??'')) redirect(is_admin()?'/admin/index.php':'/user/dashboard.php'); else $error='Invalid credentials or too many attempts.'; } $title='Login'; require __DIR__.'/includes/header.php'; ?>
<section class="py-5"><div class="container"><div class="glass-card p-4 mx-auto" style="max-width:480px"><h1>Login</h1><?php if($error):?><div class="alert alert-danger"><?=e($error)?></div><?php endif;?><form method="post" class="vstack gap-3"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="email" required name="email" class="form-control" placeholder="Email"><input type="password" required name="password" class="form-control" placeholder="Password"><button class="btn btn-gradient">Login</button><a href="/forgot-password.php">Forgot Password?</a></form></div></div></section><?php require __DIR__.'/includes/footer.php'; ?>
